label("$B$",B,SE);
label("$C$",C,NE);
label("$D$",D,NW);
label("$F$",F,SE);
label("$G$",G,SW);
label("$E$",I,N);
label("1",(0.5,3),N);
label("2",(4,3),N);
label("3",(0,1.5),W);
label("3",(5,1.5),E);
label("5",(2.5,0),S);
draw(I--H,linewidth(0.7));
label("$H$",H,S);
[/asy]

