draw((-.3,-3)--(.1,1)--(-1,0)--(3,0)--cycle);
label("$A$",(.1,1),N);
label("$B$",(-1,0),W);
label("$C$",(0,0),NE);
label("$D$",(3,0),E);
label("$E$",(-.3,-3),S);
[/asy]

